import path from "node:path"

import { TypeDefKind } from "../../api/client.gen.js"
import { DaggerArgument } from "./dagger_module/argument.js"
import { DaggerConstructor } from "./dagger_module/constructor.js"
import { DaggerFunction } from "./dagger_module/function.js"
import { DaggerModule } from "./dagger_module/module.js"
import { DaggerObjectBase } from "./dagger_module/objectBase.js"
import {
  EnumTypeDef,
  ListTypeDef,
  ObjectTypeDef,
  TypeDef,
} from "./typedef.js"

/**
 * Emit a static `__dagger.entrypoint.ts` source file from a parsed
 * DaggerModule. The generated file mirrors what the Go SDK does in
 * `cmd/codegen/generator/go/templates/modules.go:moduleMainSrc` — a static
 * dispatch (switch/case) that imports user classes directly and avoids the
 * runtime AST/reflection path.
 *
 * The emitted file is written at the module root (next to dagger.json) and
 * imports user source from `./src/...`.
 */
export function emitEntrypoint(
  module: DaggerModule,
  opts: EmitOptions,
): string {
  const ctx = new EmitContext(module, opts)

  const importsBlock = ctx.renderImports()
  const registerBlock = ctx.renderRegister()
  const dispatchBlock = ctx.renderDispatch()
  const helpersBlock = ctx.renderHelpers()

  return `// AUTO-GENERATED — DO NOT EDIT.
// Generated by Dagger TypeScript SDK introspector.
${importsBlock}

${helpersBlock}

${registerBlock}

${dispatchBlock}

dispatch().catch((e) => {
  console.error(e)
  process.exit(2)
})
`
}

export interface EmitOptions {
  /**
   * Path to the user's source directory, relative to the module root.
   * Used to compute import paths in the generated file. Defaults to "src".
   */
  sourceDir?: string

  /**
   * Path to the SDK client file, relative to the module root.
   * Defaults to "@dagger.io/dagger" (bare specifier).
   */
  sdkImportPath?: string

  /**
   * Absolute path of the module root (used to resolve relative imports for
   * each user class declared with @object).
   */
  moduleRoot?: string
}

class EmitContext {
  private readonly imports = new Map<string, Set<string>>()

  constructor(
    private readonly module: DaggerModule,
    private readonly opts: EmitOptions,
  ) {
    const sdk = opts.sdkImportPath ?? "@dagger.io/dagger"
    this.addImport(sdk, "dag")
    this.addImport(sdk, "TypeDefKind")
    this.addImport(sdk, "FunctionCachePolicy")
    this.addImport(sdk, "connection")
    this.addImport(sdk, "Error as DaggerError")
    this.addImport(`${sdk}/telemetry`, "* as telemetry", true)

    // Plan imports for every @object class so user types are statically bound.
    for (const obj of Object.values(this.module.objects)) {
      const importPath = this.userImportPath(obj)
      this.addImport(importPath, obj.name)
    }
  }

  private addImport(from: string, name: string, namespace = false) {
    if (!this.imports.has(from)) {
      this.imports.set(from, new Set())
    }
    const set = this.imports.get(from)!
    set.add(namespace ? `__NS:${name}` : name)
  }

  private userImportPath(obj: DaggerObjectBase): string {
    const loc = obj.getLocation()
    const moduleRoot = this.opts.moduleRoot
    if (moduleRoot) {
      let rel = path.relative(moduleRoot, loc.filepath)
      // Strip extension.
      rel = rel.replace(/\.(ts|mts|tsx)$/, "")
      // Always use POSIX-style separators in TS imports.
      rel = rel.split(path.sep).join("/")
      if (!rel.startsWith(".")) {
        rel = "./" + rel
      }
      return rel
    }
    // Fallback: assume sources live under `<sourceDir>/index.ts`.
    return `./${this.opts.sourceDir ?? "src"}/index`
  }

  renderImports(): string {
    const lines: string[] = []
    for (const [from, names] of this.imports) {
      const namespaceImports = [...names].filter((n) => n.startsWith("__NS:"))
      const namedImports = [...names].filter((n) => !n.startsWith("__NS:"))

      if (namespaceImports.length > 0) {
        for (const ns of namespaceImports) {
          lines.push(
            `import ${ns.slice("__NS:".length)} from "${from}"`,
          )
        }
      }
      if (namedImports.length > 0) {
        // Stable sort for determinism.
        namedImports.sort()
        lines.push(
          `import { ${namedImports.join(", ")} } from "${from}"`,
        )
      }
    }
    return lines.join("\n")
  }

  renderHelpers(): string {
    return `function formatError(e: unknown): DaggerError {
  if (e instanceof Error) {
    let error = dag.error(e.message)
    const ext = (e as { extensions?: Record<string, unknown> }).extensions
    if (ext) {
      for (const [k, v] of Object.entries(ext)) {
        if (v !== "" && v !== undefined && v !== null) {
          error = error.withValue(
            k,
            JSON.stringify(v) as string & { __JSON: never },
          )
        }
      }
    }
    return error
  }
  try {
    return dag.error(JSON.stringify(e))
  } catch {
    return dag.error(String(e))
  }
}

function rebuildClass<T>(cls: { new(...args: any[]): T; prototype: any }, state: unknown): T {
  if (state === null || state === undefined) {
    return new cls()
  }
  return Object.assign(Object.create(cls.prototype), state) as T
}

function jsonDefault<T>(s: string): T {
  return JSON.parse(s) as T
}
`
  }

  renderRegister(): string {
    const lines: string[] = []
    lines.push(`async function register(): Promise<string> {`)
    lines.push(`  let mod = dag.module_()`)

    if (this.module.description) {
      lines.push(
        `  mod = mod.withDescription(${jsStringLit(this.module.description)})`,
      )
    }

    for (const obj of Object.values(this.module.objects)) {
      lines.push(...indent(this.renderObjectRegistration(obj), "  "))
    }

    for (const enum_ of Object.values(this.module.enums)) {
      lines.push(...indent(this.renderEnumRegistration(enum_), "  "))
    }

    lines.push(`  return await mod.id()`)
    lines.push(`}`)
    return lines.join("\n")
  }

  private renderObjectRegistration(obj: DaggerObjectBase): string[] {
    const lines: string[] = []
    const v = `obj_${obj.name}`
    const opts: Record<string, string> = {}
    if (obj.description) opts.description = jsStringLit(obj.description)
    if (obj.deprecated) opts.deprecated = jsStringLit(obj.deprecated)

    lines.push(
      `let ${v} = dag.typeDef().withObject(${jsStringLit(obj.name)}${
        Object.keys(opts).length ? `, ${objLit(opts)}` : ""
      })`,
    )

    for (const method of Object.values(obj.methods)) {
      const fnExpr = this.renderFunctionExpr(method)
      lines.push(`${v} = ${v}.withFunction(${fnExpr})`)
    }

    for (const prop of Object.values(obj.properties)) {
      if (!prop.isExposed) continue
      const fieldOpts: Record<string, string> = {}
      if (prop.description) fieldOpts.description = jsStringLit(prop.description)
      if (prop.deprecated) fieldOpts.deprecated = jsStringLit(prop.deprecated)
      const fieldName = prop.alias ?? prop.name
      const td = this.renderTypeDef(prop.type!)
      lines.push(
        `${v} = ${v}.withField(${jsStringLit(fieldName)}, ${td}${
          Object.keys(fieldOpts).length ? `, ${objLit(fieldOpts)}` : ""
        })`,
      )
    }

    if (obj._constructor) {
      const ctorExpr = this.renderConstructorExpr(obj, obj._constructor, v)
      lines.push(`${v} = ${v}.withConstructor(${ctorExpr})`)
    }

    lines.push(`mod = mod.withObject(${v})`)
    return lines
  }

  private renderEnumRegistration(enum_: {
    name: string
    description: string
    values: { [name: string]: { name: string; value: string; description: string; deprecated?: string } }
  }): string[] {
    const lines: string[] = []
    const v = `enum_${enum_.name}`
    const opts: Record<string, string> = {}
    if (enum_.description) opts.description = jsStringLit(enum_.description)
    lines.push(
      `let ${v} = dag.typeDef().withEnum(${jsStringLit(enum_.name)}${
        Object.keys(opts).length ? `, ${objLit(opts)}` : ""
      })`,
    )
    for (const value of Object.values(enum_.values)) {
      const memOpts: Record<string, string> = {
        value: jsStringLit(value.value),
      }
      if (value.description) memOpts.description = jsStringLit(value.description)
      if (value.deprecated) memOpts.deprecated = jsStringLit(value.deprecated)
      lines.push(
        `${v} = ${v}.withEnumMember(${jsStringLit(value.name)}, ${objLit(memOpts)})`,
      )
    }
    lines.push(`mod = mod.withEnum(${v})`)
    return lines
  }

  private renderFunctionExpr(fn: DaggerFunction): string {
    const fnName = fn.alias ?? fn.name
    const ret = this.renderTypeDef(fn.returnType!)

    const parts: string[] = []
    parts.push(
      `dag.function_(${jsStringLit(fnName)}, ${ret})`,
    )
    if (fn.description) {
      parts.push(`.withDescription(${jsStringLit(fn.description)})`)
    }

    for (const arg of Object.values(fn.arguments)) {
      parts.push(this.renderArgCall(arg))
    }

    switch (fn.cache) {
      case "never":
        parts.push(`.withCachePolicy(FunctionCachePolicy.Never)`)
        break
      case "session":
        parts.push(`.withCachePolicy(FunctionCachePolicy.PerSession)`)
        break
      case "":
      case undefined:
        break
      default:
        parts.push(
          `.withCachePolicy(FunctionCachePolicy.Default, { timeToLive: ${jsStringLit(fn.cache)} })`,
        )
    }
    if (fn.deprecated) {
      parts.push(
        `.withDeprecated({ reason: ${jsStringLit(fn.deprecated)} })`,
      )
    }
    if (fn.isCheck) parts.push(`.withCheck()`)
    if (fn.isGenerator) parts.push(`.withGenerator()`)
    if (fn.isUp) parts.push(`.withUp()`)
    return parts.join("")
  }

  private renderConstructorExpr(
    _obj: DaggerObjectBase,
    ctor: DaggerConstructor,
    typeDefVar: string,
  ): string {
    const parts: string[] = [
      `dag.function_("", ${typeDefVar})`,
    ]
    for (const arg of Object.values(ctor.arguments)) {
      parts.push(this.renderArgCall(arg))
    }
    return parts.join("")
  }

  private renderArgCall(arg: DaggerArgument): string {
    const opts: Record<string, string> = {}
    if (arg.description) opts.description = jsStringLit(arg.description)
    if (arg.deprecated) opts.deprecated = jsStringLit(arg.deprecated)
    if (arg.defaultPath) opts.defaultPath = jsStringLit(arg.defaultPath)
    if (arg.defaultAddress) opts.defaultAddress = jsStringLit(arg.defaultAddress)
    if (arg.ignore) {
      opts.ignore = `[${arg.ignore.map(jsStringLit).join(", ")}]`
    }

    let td = this.renderTypeDef(arg.type!)
    if (arg.isOptional) {
      td = `${td}.withOptional(true)`
    }

    if (arg.defaultValue !== undefined) {
      const dv = this.resolveDefaultValue(arg)
      if (dv === undefined) {
        if (!arg.isOptional) {
          td = `${td}.withOptional(true)`
        }
      } else {
        opts.defaultValue = `JSON.stringify(${jsLiteral(dv)}) as string & { __JSON: never }`
      }
    }

    const optsLit = Object.keys(opts).length ? `, ${objLit(opts)}` : ""
    return `.withArg(${jsStringLit(arg.name)}, ${td}${optsLit})`
  }

  private resolveDefaultValue(arg: DaggerArgument): unknown | undefined {
    if (!isPrimitive(arg.type!)) return undefined
    if (arg.type!.kind !== TypeDefKind.EnumKind) return arg.defaultValue
    const enumName = (arg.type as EnumTypeDef).name
    const e = this.module.enums[enumName]
    if (!e) return arg.defaultValue
    const member = Object.entries(e.values).find(
      ([, m]) => m.value === arg.defaultValue,
    )
    return member ? member[0] : undefined
  }

  private renderTypeDef(type: TypeDef<TypeDefKind>): string {
    switch (type.kind) {
      case TypeDefKind.ScalarKind:
        return `dag.typeDef().withScalar(${jsStringLit((type as { name: string }).name)})`
      case TypeDefKind.ObjectKind:
        return `dag.typeDef().withObject(${jsStringLit((type as ObjectTypeDef).name)})`
      case TypeDefKind.ListKind:
        return `dag.typeDef().withListOf(${this.renderTypeDef((type as ListTypeDef).typeDef)})`
      case TypeDefKind.VoidKind:
        return `dag.typeDef().withKind(TypeDefKind.VoidKind).withOptional(true)`
      case TypeDefKind.EnumKind:
        return `dag.typeDef().withEnum(${jsStringLit((type as EnumTypeDef).name)})`
      case TypeDefKind.InterfaceKind:
        return `dag.typeDef().withInterface(${jsStringLit((type as { name: string }).name)})`
      case TypeDefKind.StringKind:
        return `dag.typeDef().withKind(TypeDefKind.StringKind)`
      case TypeDefKind.IntegerKind:
        return `dag.typeDef().withKind(TypeDefKind.IntegerKind)`
      case TypeDefKind.FloatKind:
        return `dag.typeDef().withKind(TypeDefKind.FloatKind)`
      case TypeDefKind.BooleanKind:
        return `dag.typeDef().withKind(TypeDefKind.BooleanKind)`
      default:
        throw new Error(`unsupported TypeDefKind ${type.kind}`)
    }
  }

  renderDispatch(): string {
    const lines: string[] = []
    lines.push(`async function invoke(`)
    lines.push(`  parentName: string,`)
    lines.push(`  fnName: string,`)
    lines.push(`  parentJson: any,`)
    lines.push(`  args: Record<string, any>,`)
    lines.push(`): Promise<any> {`)
    lines.push(`  switch (parentName) {`)

    const objNames = Object.keys(this.module.objects).sort()
    for (const objName of objNames) {
      const obj = this.module.objects[objName]
      lines.push(`    case ${jsStringLit(objName)}: {`)
      lines.push(`      switch (fnName) {`)

      // Constructor (fnName === "")
      if (obj._constructor) {
        lines.push(...indent(this.renderConstructorCase(obj), "        "))
      } else {
        lines.push(`        case "": {`)
        lines.push(`          return new ${obj.name}()`)
        lines.push(`        }`)
      }

      const methodNames = Object.keys(obj.methods).sort()
      for (const methodName of methodNames) {
        lines.push(...indent(this.renderMethodCase(obj, obj.methods[methodName]), "        "))
      }

      lines.push(`        default:`)
      lines.push(`          throw new Error(\`unknown function \${fnName} on ${obj.name}\`)`)
      lines.push(`      }`)
      lines.push(`    }`)
    }

    lines.push(`    default:`)
    lines.push(`      throw new Error(\`unknown object \${parentName}\`)`)
    lines.push(`  }`)
    lines.push(`}`)

    lines.push(``)
    lines.push(`async function dispatch() {`)
    lines.push(`  await connection(async () => {`)
    lines.push(`    const fnCall = dag.currentFunctionCall()`)
    lines.push(`    const parentName = await fnCall.parentName()`)
    lines.push(``)
    lines.push(`    if (parentName === "") {`)
    lines.push(`      const id = await register()`)
    lines.push(`      await fnCall.returnValue(JSON.stringify(id) as string & { __JSON: never })`)
    lines.push(`      return`)
    lines.push(`    }`)
    lines.push(``)
    lines.push(`    const fnName = await fnCall.name()`)
    lines.push(`    const parentJson = JSON.parse(await fnCall.parent())`)
    lines.push(`    const fnArgs = await fnCall.inputArgs()`)
    lines.push(``)
    lines.push(`    const args: Record<string, any> = {}`)
    lines.push(`    for (const arg of fnArgs) {`)
    lines.push(`      args[await arg.name()] = JSON.parse(await arg.value())`)
    lines.push(`    }`)
    lines.push(``)
    lines.push(`    try {`)
    lines.push(`      const result = await invoke(parentName, fnName, parentJson, args)`)
    lines.push(`      const out = result === undefined || result === null ? "null" : JSON.stringify(result)`)
    lines.push(`      await fnCall.returnValue(out as string & { __JSON: never })`)
    lines.push(`    } catch (e: unknown) {`)
    lines.push(`      await fnCall.returnError(formatError(e))`)
    lines.push(`      process.exit(1)`)
    lines.push(`    }`)
    lines.push(`  }, { LogOutput: process.stdout })`)
    lines.push(`}`)

    return lines.join("\n")
  }

  private renderConstructorCase(obj: DaggerObjectBase): string[] {
    const ctor = obj._constructor!
    const lines: string[] = []
    lines.push(`case "": {`)
    const callArgs: string[] = []
    for (const arg of Object.values(ctor.arguments)) {
      lines.push(...this.renderArgCoercion(arg))
      callArgs.push(coercedVarName(arg))
    }
    lines.push(`  return new ${obj.name}(${callArgs.join(", ")})`)
    lines.push(`}`)
    return lines
  }

  private renderMethodCase(obj: DaggerObjectBase, method: DaggerFunction): string[] {
    const lines: string[] = []
    const caseName = method.alias ?? method.name
    lines.push(`case ${jsStringLit(caseName)}: {`)
    lines.push(`  const __parent = rebuildClass(${obj.name}, parentJson)`)

    const callArgs: string[] = []
    for (const arg of Object.values(method.arguments)) {
      lines.push(...this.renderArgCoercion(arg))
      const v = coercedVarName(arg)
      callArgs.push(arg.isVariadic ? `...${v}` : v)
    }

    lines.push(`  const __result = await __parent.${method.name}(${callArgs.join(", ")})`)

    if (method.returnType) {
      lines.push(...this.renderReturnSerialization(method.returnType))
    } else {
      lines.push(`  return null`)
    }
    lines.push(`}`)
    return lines
  }

  private renderArgCoercion(arg: DaggerArgument): string[] {
    const v = coercedVarName(arg)
    const lines: string[] = []
    const access = `args[${jsStringLit(arg.name)}]`

    if (arg.defaultValue !== undefined && isPrimitive(arg.type!)) {
      // Engine resolves primitive defaults; we only need to coerce.
      lines.push(`  const ${v} = ${this.coerceExpr(access, arg.type!)}`)
      return lines
    }

    // Argument may be undefined (optional) — keep as undefined; otherwise coerce.
    lines.push(
      `  const ${v} = ${access} === undefined || ${access} === null ? ${access} : ${this.coerceExpr(access, arg.type!)}`,
    )
    return lines
  }

  /**
   * Render an expression that converts a JSON-decoded value (`expr`) into the
   * native runtime value the user method expects.
   */
  private coerceExpr(expr: string, type: TypeDef<TypeDefKind>): string {
    switch (type.kind) {
      case TypeDefKind.StringKind:
      case TypeDefKind.IntegerKind:
      case TypeDefKind.FloatKind:
      case TypeDefKind.BooleanKind:
      case TypeDefKind.ScalarKind:
      case TypeDefKind.VoidKind:
        return expr
      case TypeDefKind.ListKind: {
        const inner = (type as ListTypeDef).typeDef
        return `(${expr} as any[]).map((__v) => ${this.coerceExpr("__v", inner)})`
      }
      case TypeDefKind.ObjectKind: {
        const name = (type as ObjectTypeDef).name
        if (this.module.objects[name]) {
          // Module-defined object — rebuild from state.
          return `rebuildClass(${name}, ${expr})`
        }
        // Core IDable object — use dag.loadXFromID.
        return `dag.load${name}FromID(${expr})`
      }
      case TypeDefKind.EnumKind: {
        const name = (type as EnumTypeDef).name
        const e = this.module.enums[name]
        if (!e) return expr
        // Build a map literal name -> value.
        const entries = Object.values(e.values)
          .map((v) => `${jsStringLit(v.name)}: ${jsStringLit(v.value)}`)
          .join(", ")
        return `({ ${entries} } as Record<string, string>)[${expr}] ?? ${expr}`
      }
      case TypeDefKind.InterfaceKind:
        return `(${expr} /* TODO: interface coercion */)`
      default:
        return expr
    }
  }

  private renderReturnSerialization(type: TypeDef<TypeDefKind>): string[] {
    return [`  return ${this.serializeExpr("__result", type)}`]
  }

  private serializeExpr(expr: string, type: TypeDef<TypeDefKind>): string {
    switch (type.kind) {
      case TypeDefKind.StringKind:
      case TypeDefKind.IntegerKind:
      case TypeDefKind.FloatKind:
      case TypeDefKind.BooleanKind:
      case TypeDefKind.ScalarKind:
      case TypeDefKind.VoidKind:
        return expr
      case TypeDefKind.ListKind: {
        const inner = (type as ListTypeDef).typeDef
        return `await Promise.all((${expr} as any[]).map(async (__v) => ${this.serializeExpr("__v", inner)}))`
      }
      case TypeDefKind.ObjectKind: {
        const name = (type as ObjectTypeDef).name
        if (this.module.objects[name]) {
          // Module-defined object — return state as a plain object using
          // the property aliases we registered. For minimal first pass we
          // return the instance as-is; JSON.stringify will serialize own
          // enumerable props.
          return expr
        }
        // Core IDable — call .id() to serialize.
        return `await (${expr}).id()`
      }
      case TypeDefKind.EnumKind: {
        const name = (type as EnumTypeDef).name
        const e = this.module.enums[name]
        if (!e) return expr
        const entries = Object.values(e.values)
          .map((v) => `${jsStringLit(v.value)}: ${jsStringLit(v.name)}`)
          .join(", ")
        return `({ ${entries} } as Record<string, string>)[${expr}] ?? ${expr}`
      }
      case TypeDefKind.InterfaceKind:
        return `(${expr} /* TODO: interface return */)`
      default:
        return expr
    }
  }
}

function isPrimitive(type: TypeDef<TypeDefKind>): boolean {
  return (
    type.kind === TypeDefKind.BooleanKind ||
    type.kind === TypeDefKind.IntegerKind ||
    type.kind === TypeDefKind.StringKind ||
    type.kind === TypeDefKind.FloatKind ||
    type.kind === TypeDefKind.EnumKind
  )
}

function coercedVarName(arg: DaggerArgument): string {
  return `__arg_${arg.name}`
}

function jsStringLit(s: string): string {
  return JSON.stringify(s)
}

function jsLiteral(v: unknown): string {
  return JSON.stringify(v)
}

function objLit(props: Record<string, string>): string {
  const parts: string[] = []
  for (const [k, v] of Object.entries(props)) {
    parts.push(`${k}: ${v}`)
  }
  return `{ ${parts.join(", ")} }`
}

function indent(lines: string[], prefix: string): string[] {
  return lines.map((l) => (l.length ? prefix + l : l))
}
